<?php
/* Plugin Name: Custom Authentication */

if (!defined('ABSPATH')) {
    exit; // Exit if accessed directly.
}

add_action('init', 'register_custom_user');
add_action('authenticate', 'authenticate_user');
add_filter('login_errors', 'custom_login_error');

function register_custom_user() {
    register_new_user();
}

function authenticate_user($username, $password) {
    global $wpdb;
    $user = get_user_by('login', $username);

    if ($user && wp_check_password($password, $user->data->user_pass, $user->ID)) {
        return $user;
    }

    return null;
}

function register_new_user() {
    global $wpdb;

    if (isset($_POST['submit'])) {
        $username = sanitize_user($_POST['username']);
        $email = sanitize_email($_POST['email']);
        $password = wp_hash_password($_POST['password']);

        $user_id = wp_insert_user(array(
            'user_login' => $username,
            'user_email' => $email,
            'user_pass' => $password
        ));

        if (is_wp_error($user_id)) {
            // Handle error.
        } else {
            // Successfully registered the user.
        }
    }
}

function custom_login_error($errors) {
    if (!empty($errors)) {
        $errors = "<p><strong>Error:</strong> " . implode('<br>', $errors) . "</p>";
    }

    return $errors;
}